isDisabled:
{{ 
  // O botão DELETAR fica DESABILITADO (true) se:
  (
    // 1. Estiver no modo ADICIONAR
    (appsmith.store.modalContexto?.entidade === 'PET' && appsmith.store.modalContexto?.acaoTipo === "ADICIONAR") || 

    // 2. OU se houver qualquer alteração nos campos (usuário começou a editar)
    JSvalidateButtonPET.temAlteracaoPET() ||

    // 3. OU se não houver um ID válido
    !appsmith.store.petSelecionado?.ani002_id
  )
}}

onClick:
{{
  (() => {
    // 1. Manutenção de sessão
    JSutils.resetInactivityTimer();

    // 2. Definimos a fonte dos dados (Store é nossa âncora de segurança)
    const petParaDeletar = appsmith.store.petSelecionado;

    // 3. Validação de segurança: Existe um ID para deletar?
    if (!petParaDeletar?.ani002_id) {
      return showAlert("Selecione um registro para excluir.", "warning");
    }

    // 4. Dispara o Modal de Confirmação
    return JSconfirmationPET.showModal({
      action: "Delete",
      message: `Deseja realmente EXCLUIR o registro de "${petParaDeletar.ani002_nome}"?`,
      icon: "trash",
      color: "red",
      row: petParaDeletar // Passamos o objeto completo para a query de delete se necessário
    });
  })()
}}
